import React from "react";
import { SERVICES, WA_LINK } from "../../data/constants";
import SvcIcon from "../ui/SvcIcon";
import PageHero from "../ui/PageHero";

const ICONS = {
  IT:       { emoji: "💻", bg: "linear-gradient(135deg,#0284C7,#0EA5E9)" },
  NonIT:    { emoji: "👥", bg: "linear-gradient(135deg,#059669,#10B981)" },
  Payroll:  { emoji: "📊", bg: "linear-gradient(135deg,#7C3AED,#A78BFA)" },
  Software: { emoji: "⚙️", bg: "linear-gradient(135deg,#DC2626,#F87171)" },
  BPO:      { emoji: "📞", bg: "linear-gradient(135deg,#0369A1,#38BDF8)" },
};

// ── Sub Card with image ───────────────────────────────────────────────────
function SubCard({ sub, color, index }) {
  const [hov, setHov] = React.useState(false);
  return (
    <div
      onMouseEnter={() => setHov(true)}
      onMouseLeave={() => setHov(false)}
      style={{
        borderRadius: 20, overflow: "hidden", background: "#fff",
        border: `1.5px solid ${hov ? color : "#E8EEFF"}`,
        boxShadow: hov ? `0 16px 48px ${color}22` : "0 2px 16px rgba(0,0,0,0.05)",
        transition: "all 0.3s cubic-bezier(0.4,0,0.2,1)",
        transform: hov ? "translateY(-6px)" : "none",
      }}
    >
      {/* Image */}
      <div style={{ height: 180, position: "relative", overflow: "hidden" }}>
        <img
          src={sub.img} alt={sub.title}
          style={{ width: "100%", height: "100%", objectFit: "cover", objectPosition: sub.imgPos || "center", display: "block", transition: "transform 0.4s", transform: hov ? "scale(1.06)" : "scale(1)" }}
        />
        <div style={{ position: "absolute", inset: 0, background: `linear-gradient(to bottom, transparent 20%, ${color}CC)` }} />
        <div style={{ position: "absolute", top: 12, left: 12, width: 32, height: 32, borderRadius: 10, background: "rgba(255,255,255,0.2)", backdropFilter: "blur(8px)", border: "1px solid rgba(255,255,255,0.3)", display: "flex", alignItems: "center", justifyContent: "center" }}>
          <span style={{ fontWeight: 900, fontSize: 13, color: "#fff" }}>{index + 1}</span>
        </div>
        <h3 style={{ position: "absolute", bottom: 14, left: 16, right: 12, fontWeight: 800, fontSize: "clamp(12px,1.6vw,14px)", color: "#fff", margin: 0, lineHeight: 1.3 }}>
          {sub.title}
        </h3>
      </div>
      {/* Body */}
      <div style={{ padding: "16px 18px 20px" }}>
        <p style={{ fontSize: 12.5, color: "#64748B", lineHeight: 1.75, margin: 0, fontWeight: 400 }}>
          Expert {sub.title.toLowerCase()} services tailored for your business growth.
        </p>
        <div style={{ marginTop: 12, color, fontSize: 12.5, fontWeight: 800 }}>Learn more →</div>
      </div>
    </div>
  );
}

