// ── Services List Page ────────────────────────────────────────────────────
export default function Services({ activeSvc, onService, onBack }) {
  const [hovered, setHovered] = React.useState(null);

  if (activeSvc) {
    const svc = SERVICES.find(s => s.id === activeSvc);
    if (svc) return <ServiceDetail svc={svc} onBack={onBack} />;
  }

  return (
    <div className="fu" style={{ paddingTop: "clamp(72px,9vw,130px)", background: "#F8FAFF", minHeight: "100vh" }}>

      {/* Page Hero */}
      <div style={{ background: "linear-gradient(135deg,#0369A1,#0284C7,#0EA5E9)", padding: "clamp(48px,7vw,80px) clamp(16px,4vw,48px)", position: "relative", overflow: "hidden" }}>
        <div style={{ position: "absolute", right: -100, top: -100, width: 400, height: 400, borderRadius: "50%", background: "rgba(255,255,255,0.05)", pointerEvents: "none" }} />
        <div style={{ maxWidth: 1400, margin: "0 auto", textAlign: "center", position: "relative" }}>
          <div style={{ display: "inline-flex", alignItems: "center", gap: 8, background: "rgba(255,255,255,0.15)", border: "1px solid rgba(255,255,255,0.25)", borderRadius: 50, padding: "6px 20px", marginBottom: 20 }}>
            <span style={{ fontSize: 10, fontWeight: 900, letterSpacing: 3, color: "#E0F2FE", textTransform: "uppercase" }}>⚡ Our Services</span>
          </div>
          <h1 style={{ fontWeight: 900, fontSize: "clamp(28px,5vw,54px)", color: "#fff", letterSpacing: -1.5, lineHeight: 1.15, marginBottom: 16 }}>
            Comprehensive Business<br />Solutions
          </h1>
          <p style={{ fontSize: "clamp(14px,1.6vw,18px)", color: "rgba(224,242,254,0.85)", maxWidth: 560, margin: "0 auto", lineHeight: 1.7, fontWeight: 400 }}>
            Complete recruitment, payroll, software and BPO services. Click any card to explore in detail.
          </p>
        </div>
      </div>

      {/* Service Cards with Images */}
      <div style={{ maxWidth: 1400, margin: "0 auto", padding: "clamp(48px,6vw,80px) clamp(16px,4vw,48px)" }}>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(min(100%,280px),1fr))", gap: 24 }}>
          {SERVICES.map((s, i) => {
            const ic = ICONS[s.id] || { emoji: "🔷", bg: s.color };
            const isHov = hovered === s.id;
            return (
              <div
                key={s.id}
                onClick={() => onService(s.id)}
                onMouseEnter={() => setHovered(s.id)}
                onMouseLeave={() => setHovered(null)}
                style={{
                  cursor: "pointer", borderRadius: 24, overflow: "hidden",
                  background: "#fff",
                  border: `1.5px solid ${isHov ? s.color : "#E8EEFF"}`,
                  boxShadow: isHov ? `0 24px 64px ${s.color}22` : "0 2px 20px rgba(0,0,0,0.05)",
                  transition: "all 0.3s cubic-bezier(0.4,0,0.2,1)",
                  transform: isHov ? "translateY(-10px)" : "none",
                }}
              >
                {/* Image area */}
                <div style={{ height: 200, position: "relative", overflow: "hidden" }}>
                  <img
                    src={s.img} alt={s.title}
                    style={{ width: "100%", height: "100%", objectFit: "cover", objectPosition: s.imgPos || "center", display: "block", transition: "transform 0.4s", transform: isHov ? "scale(1.06)" : "scale(1)" }}
                  />
                  {/* Gradient overlay */}
                  <div style={{ position: "absolute", inset: 0, background: isHov ? `linear-gradient(to bottom, transparent 10%, ${s.color}DD)` : "linear-gradient(to bottom, transparent 25%, rgba(0,0,0,0.65))" , transition: "all 0.3s" }} />

                  {/* Top color bar */}
                  <div style={{ position: "absolute", top: 0, left: 0, right: 0, height: 4, background: s.color }} />

                  {/* Icon + Tag overlay */}
                  <div style={{ position: "absolute", bottom: 16, left: 18, display: "flex", alignItems: "center", gap: 10 }}>
                    <div style={{ width: 40, height: 40, borderRadius: 12, background: "rgba(255,255,255,0.2)", backdropFilter: "blur(10px)", border: "1px solid rgba(255,255,255,0.3)", display: "flex", alignItems: "center", justifyContent: "center" }}>
                      <span style={{ fontSize: 20 }}>{ic.emoji}</span>
                    </div>
                    <span style={{ fontSize: 10, fontWeight: 900, color: "#fff", letterSpacing: 2, textTransform: "uppercase", textShadow: "0 1px 4px rgba(0,0,0,0.3)" }}>{s.tag}</span>
                  </div>
                </div>

                {/* Card Body */}
                <div style={{ padding: "22px 24px 26px" }}>
                  <h3 style={{ fontWeight: 900, fontSize: "clamp(16px,2vw,20px)", color: "#0F172A", marginBottom: 10, letterSpacing: -0.5, lineHeight: 1.25 }}>
                    {s.title}
                  </h3>
                  <p style={{ fontSize: 13.5, color: "#64748B", lineHeight: 1.8, marginBottom: 16, fontWeight: 400 }}>
                    {s.desc.substring(0, 95)}...
                  </p>

                  {/* Sub pills */}
                  <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginBottom: 20 }}>
                    {s.sub.slice(0, 3).map(sub => (
                      <span key={sub.title} style={{ fontSize: 10.5, fontWeight: 700, color: isHov ? s.color : "#94A3B8", background: isHov ? `${s.color}10` : "#F8FAFF", border: `1px solid ${isHov ? `${s.color}22` : "#E8EEFF"}`, padding: "4px 10px", borderRadius: 50, transition: "all 0.3s" }}>
                        {sub.title.split(" ").slice(0, 2).join(" ")}
                      </span>
                    ))}
                    <span style={{ fontSize: 10.5, fontWeight: 700, color: "#CBD5E1", background: "#F8FAFF", border: "1px solid #E8EEFF", padding: "4px 10px", borderRadius: 50 }}>
                      +{s.sub.length - 3} more
                    </span>
                  </div>

                  {/* CTA */}
                  <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", paddingTop: 16, borderTop: `1px solid ${isHov ? `${s.color}22` : "#F1F5F9"}`, transition: "border-color 0.3s" }}>
                    <span style={{ fontSize: 13.5, fontWeight: 800, color: isHov ? s.color : "#94A3B8", transition: "color 0.3s" }}>Explore Service</span>
                    <div style={{ width: 38, height: 38, borderRadius: "50%", background: isHov ? s.color : "#F1F5F9", display: "flex", alignItems: "center", justifyContent: "center", transition: "all 0.3s", transform: isHov ? "translateX(4px)" : "none", boxShadow: isHov ? `0 6px 20px ${s.color}44` : "none" }}>
                      <span style={{ fontSize: 16, color: isHov ? "#fff" : "#94A3B8" }}>→</span>
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}